  import java.util.Date;  
  import java.text.DateFormat;
  import java.time.Instant;
  import java.time.temporal.ChronoUnit;
  
  String logName = "Ascension-Rule-Rehire-Report";
  String TASKDEFINITION ="Schedule-Ascension-TaskDefinition-GenerateRehireReport";


  /**
 * Generates Rehired identity Report Data. 
 * It gets the list of identities which got rehired from the last refresh.
 * It prepares the report data for each identity.
 * @return the reportData
 */
  public List getRehiredIdentities(long startDate, long endDate, String launcher) throws GeneralException, ParseException{

    String idSamAccountName = "";
    boolean ifMatchingADAccountExists = false;
    String domainValue = "";

    String userIdDesc = "";
    String newPostionTitle ="";

    String azureUserPrincipalName="";
    String azureEnabled = "";
    String gsuitePrimaryEmail="";
    String gsuiteEnabled = "";
    String gsuiteAccountId ="";


    String adEnabled = "";
    String extAttribute6 = "";
    String msExchExtAttr40 = "";
    String distinguishedName = "";

    String firstName="";
    String lastName="";
    String samAccountName="";
    String domain="";
    String ministry="";
    String userType="";
    String line = "";
    String email = "";

    List idList = new ArrayList();
    List reportData = new ArrayList();
    List rehiredIdentitiesList = new ArrayList();
    List adAccountsList = null;    
    Iterator identitiesIterator = null;
    String lastCompletedDate= null;

    String applicationName = "";
    String displayName = "";
    String identityValueFromDB="";

    error(logName, "BEGIN: getRehiredIdentities");

    String action = "identityLifecycleEvent";
    String string1 = "Ascension-LifecycleEvent-Persona-Rehire";

    QueryOptions qo = new QueryOptions();
    Filter f = Filter.and(Filter.eq("action", action),Filter.eq("string1",string1),Filter.gt("created",new Date(startDate)),Filter.lt("created",new Date(endDate)));
    qo.setOrderBy("created");
    qo.setOrderAscending(false);
    qo.addFilter(f);    
    identitiesIterator = context.search(AuditEvent.class,qo,"target");
    boolean eligibleRehireAuditEvent = false;

    while (identitiesIterator.hasNext()) {
      Object[] identityObject = (Object[]) identitiesIterator.next();
      identityValueFromDB = identityObject[0].split(":")[1];

      Identity identity = context.getUniqueObject(Identity.class, Filter.eq("initialName", identityValueFromDB));

      if(identity!=null){
        identityValueFromDB = identity.getName();
      }  

      if(!idList.contains(identityValueFromDB)){
        idList.add(identityValueFromDB);
        eligibleRehireAuditEvent = true;
      }

    }
    debug(logName, "- No. of Rehired Identities"+idList.size());
    try{
      if(!Util.isEmpty(idList) && idList!=null){
        for(String targetIdentity: idList){
          debug(logName, "- Fetching account details for Identity - " + targetIdentity);

          adEnabled = "Not Available";
          extAttribute6 = "Not Available";
          msExchExtAttr40 = "Not Available";
          distinguishedName = "Not Available";

          azureUserPrincipalName = "Not Available";
          azureEnabled = "Not Available";

          gsuiteAccountId = "Not Available";
          gsuitePrimaryEmail = "Not Available";
          gsuiteEnabled = "Not Available";

          Identity identity = context.getObjectByName(Identity.class, targetIdentity);

          if(identity!=null){
            samAccountName = identity.getStringAttribute("samAccountName");            
            domain = identity.getStringAttribute("domain");
            newPostionTitle = identity.getStringAttribute("title");
            ministry = identity.getStringAttribute("ministry");
            firstName = identity.getStringAttribute("firstname");
            lastName = identity.getStringAttribute("lastname"); 
            userIdDesc = firstName +" "+lastName ;
            userType = identity.getStringAttribute("type");
            email = identity.getEmail();


            List auditStringCondtion = new ArrayList();
            adAccountsList = new ArrayList();
            HashMap accountDetailsMap = null;
            boolean amitaAccount = false;
            String adDisplayName = null;

            List auditString2Condtion = new ArrayList();

            // Getting account details for each identity.

            String action = "PersonaRehire";

            auditStringCondtion.add("Accounts for Reenable");
            auditStringCondtion.add("Accounts for Creation");

            auditString2Condtion.add("Market Transfer Flow is triggered");
            auditString2Condtion.add("Non-Persona Manual Action workitem is generated");

            List props = new ArrayList();
            props.add("string1");
            props.add("string2");
            props.add("string3");
            props.add("string4");

            QueryOptions qo = new QueryOptions();

            Filter f = Filter.and(Filter.eq("action", action),Filter.eq("target",targetIdentity),Filter.gt("created",new Date(startDate)),Filter.lt("created",new Date(endDate)));
            Filter auditStringFilter = Filter.or(Filter.in("string1",auditStringCondtion), Filter.in("string2",auditString2Condtion));
            Filter finalFilter = Filter.and(f,auditStringFilter);

            qo.addFilter(finalFilter);
            qo.setOrderBy("created");
            qo.setOrderAscending(false);           
            Iterator auditEventIterator = context.search(AuditEvent.class,qo,props);    

            while (auditEventIterator.hasNext()) {
              try { 
                eligibleRehireAuditEvent = true;
                ignoreRehiredEvent = false;
                Object[] auditEventObj = (Object[]) auditEventIterator.next();   
                if (null != auditEventObj) {
                  String auditEventString1 =  auditEventObj [0];
                  String auditEventString2 =  auditEventObj [1];
                  String auditEventString3 =  auditEventObj [2];

                  if (auditEventString2 != null){
                    if (("Market Transfer Flow is triggered".equalsIgnoreCase(auditEventString2)) || ("Non-Persona Manual Action workitem is generated".equalsIgnoreCase(auditEventString2))) {
                      eligibleRehireAuditEvent = false;                      
                      break;
                    } else {
                      if("AD Accounts=Not Available".equalsIgnoreCase(auditEventString2)) {
                        accountDetailsMap = new HashMap();
                        adAccountsList.add(accountDetailsMap);
                      } else { 
                        String auditString2Split = auditEventString2.split("=")[1];
                        String[] auditString2IndividualaccountArray = auditString2Split.split(",");
                        List valueList = Arrays.asList(auditString2IndividualaccountArray);
                        if (auditString2IndividualaccountArray != null && auditString2IndividualaccountArray.length > 0) {              
                          for (String account: valueList) {
                            if (account.startsWith("AD-AMITA")) {
                              amitaAccount = true;
                            } 
                          }
                        } 
                        for (String auditString2Individualaccount: auditString2IndividualaccountArray)  {
                          String auditAppName = auditString2Individualaccount.split(":")[0];
                          String adAuditDisplayName = auditString2Individualaccount.split(":")[1];
                          if (amitaAccount) { 
                            if ("AD-AMITA".equalsIgnoreCase(auditAppName) ) {
                              adAccountsList = getAccountDetails(auditAppName,adAuditDisplayName,identity,adAccountsList);
                              break;  
                            }  
                          } else {
                            adAccountsList = getAccountDetails(auditAppName,adAuditDisplayName,identity,adAccountsList);
                          } 
                        }
                      }
                    }
                  }
                }
              } catch(Exception e) {
                error(logName, "ERROR: In getRehiredIdentities inner loop : ",e );
              }

            }
            debug(logName, "END: While loop"+adAccountsList);
            if (eligibleRehireAuditEvent) {
              Application azureApp = context.getObjectByName(Application.class, "Azure");
              IdentityService idSvc = new IdentityService(context);         
              List azureLinksList = idSvc.getLinks(identity, azureApp);     
              if(!Util.isEmpty(azureLinksList) && azureLinksList.get(0) != null){
                Link azureLink = azureLinksList.get(0);
                azureUserPrincipalName = azureLink.getAttribute("userPrincipalName");
                if(azureUserprincipalName!=null && Util.nullSafeCaseInsensitiveEq(identity.getAttribute("email"),azureUserPrincipalName)){
                  if(azureLink.getIiqDisabled()){
                    azureEnabled = "TRUE";
                  } else{
                    azureEnabled = "FALSE";
                  }

                }
              }
              Application gsuiteApp = context.getObjectByName(Application.class, "GSuite");
              IdentityService idSvc = new IdentityService(context);
              List gsuiteLinksList = idSvc.getLinks(identity, gsuiteApp);
              if(!Util.isEmpty(gsuiteLinksList) && gsuiteLinksList.get(0) != null){
                Link gsuiteLink = gsuiteLinksList.get(0);
                gsuitePrimaryEmail = gsuiteLink.getAttribute("primaryEmail");
                if(gsuitePrimaryEmail!=null && Util.nullSafeCaseInsensitiveEq(identity.getAttribute("email"),gsuitePrimaryEmail)){
                  if(gsuiteLink.getIiqDisabled()){
                    gsuiteEnabled = "FALSE";
                  } else{
                    gsuiteEnabled = "TRUE";
                  }
                }
                gsuiteAccountId = gsuiteLink.getNativeIdentity();
              } 
              if ( adAccountsList != null && adAccountsList.size() > 0 ) { 
                for (HashMap accountDetailsMapReport: adAccountsList ) {
                  if (accountDetailsMapReport .get( "isAccountEnabled" )  != null ) {
                    adEnabled = String.valueOf(accountDetailsMapReport.get("isAccountEnabled"));
                  }   
                  adEnabled = adEnabled != null ? adEnabled:"Not Available";
                  distinguishedName = accountDetailsMapReport.get("distinguishedName") !=null ? accountDetailsMapReport.get("distinguishedName").toString():"Not Available";
                  extAttribute6 = accountDetailsMapReport.get("extAttribute6") !=null ? accountDetailsMapReport.get("extAttribute6").toString():"Not Available";
                  msExchExtAttr40 = accountDetailsMapReport.get("msExchExtAttr40") !=null ? accountDetailsMapReport.get("msExchExtAttr40").toString():"Not Available";
                  applicationName = accountDetailsMapReport.get("adAppName")!=null ? accountDetailsMapReport.get("adAppName").toString():"Not Available";
                  displayName = accountDetailsMapReport.get("accountDisplayName")!=null ? accountDetailsMapReport.get("accountDisplayName"):"Not Available";
                  line = targetIdentity+","+samAccountName+","+applicationName+","+email+","+displayName+","+domain+","+newPostionTitle+","+ministry+","+userIdDesc+","+userType+","+adEnabled+",\""+distinguishedName+"\","+extAttribute6+","+msExchExtAttr40+","+azureUserPrincipalName+","+azureEnabled+","+gsuitePrimaryEmail+","+gsuiteEnabled+","+gsuiteAccountId;
                  reportData.add(line); 
                  rehiredIdentitiesList.add(targetIdentity);
                } 
              } else {
                line = targetIdentity+","+samAccountName+","+applicationName+","+email+","+displayName+","+domain+","+newPostionTitle+","+ministry+","+userIdDesc+","+userType+","+adEnabled+",\""+distinguishedName+"\","+extAttribute6+","+msExchExtAttr40+","+azureUserPrincipalName+","+azureEnabled+","+gsuitePrimaryEmail+","+gsuiteEnabled+","+gsuiteAccountId;
                reportData.add(line); 
                rehiredIdentitiesList.add(targetIdentity);
              } 

            } 
          }
        }
      }
      error(logName, "REPORTDATA ::     "+  reportData.size());


      Date date = new Date(startDate);
      DateFormat formatter = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss a");
      String strdateFormatted = formatter.format(date);

      Date edate = new Date(endDate);
      DateFormat formatter = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss a");
      String enddateFormatted = formatter.format(edate);

      taskResult.setAttribute("identityCount",reportData.size());
      taskResult.setAttribute("identitiesRehired", rehiredIdentitiesList);
      taskResult.setAttribute("launcher",launcher);
      taskResult.setAttribute("StartDate",strdateFormatted);
      taskResult.setAttribute("EndDate",enddateFormatted);

      context.saveObject(taskResult);
      context.commitTransaction();

    }catch(Exception e) {
      error(logName, "ERROR: In getRehiredIdentities: ",e );
    }finally{
      sailpoint.tools.Util.flushIterator(identitiesIterator);
    }

    return reportData; 
  }



  /**
 * This method generates the AD account details for the Rehired identities
 * @param auditAppName
 * @param auditDisplayName
 * @param identity
 * @param adAccountsList
 * @return the accountDetails
 */

  public List getAccountDetails(String auditAppName,String adAuditDisplayName,Identity identity,List adAccountsList){

    debug(logName, "BEGIN:: getAccountDetails ");
    Application appName = context.getObjectByName(Application.class, auditAppName);
    IdentityService idSvc = new IdentityService(context);   
    List adAppList = idSvc.getLinks(identity, appName);
    Map accountDetailsMap = null;
    if(!Util.isEmpty(adAppList)){
      for (Link adLink: adAppList) {
        adDisplayName = adLink.getDisplayName();
        accountDetailsMap = new HashMap();
        if(Util.nullSafeCaseInsensitiveEq(adDisplayName, adAuditDisplayName)){  
          accountDetailsMap.put("adAppName",auditAppName);
          accountDetailsMap.put("accountDisplayName",adDisplayName);
          if(adLink.getIiqDisabled()){
            accountDetailsMap.put("isAccountEnabled", "FALSE");
          } else{
            accountDetailsMap.put("isAccountEnabled", "TRUE");

          }
          accountDetailsMap. put("isAccountEnabled", adLink.isDisabled());
          accountDetailsMap.put("distinguishedName", adLink.getAttribute("distinguishedName"));
          accountDetailsMap.put("extAttribute6", adLink.getAttribute("extensionAttribute6"));
          accountDetailsMap.put("msExchExtAttr40", adLink.getAttribute("msExchExtensionAttribute40"));
          
          adAccountsList.add(accountDetailsMap);
        }
        
      } 
    }
    return adAccountsList;
  }


  /**
 * This method sends email with the report.
 * @param finalDataMap
 * @param toAddress
 * @return 
 */
  public boolean sendEmail(Map finalDataMap, String toAddress,long startDate,long endDate){
    String finalRecords = null;
    Map mailargs = new HashMap();;
    String strTemplate = "Ascension-EmailTemplate-Rehire-Report-Notification";
    Date currentDate = new Date(); 
    SimpleDateFormat dateFormat = new SimpleDateFormat("MM-dd-yyyy HH:mm:ss a"); 
    String currentDateTime = dateFormat.format(currentDate);
    String startDateOnEmail = dateFormat.format(startDate);
    String endDateOnEmail = dateFormat.format(endDate);

    String fileName =  "Rehire-Report-"+ currentDateTime + ".csv";
    EmailTemplate template = context.getObjectByName(EmailTemplate.class, strTemplate);
    EmailOptions mailopts = null;
    EmailFileAttachment attachment = null;
    dataBuilder = new StringBuilder();
    dataBuilder.append("\"Index\",\"IdentityName\",\"SamAccountName\",\"Application Name\",\"Email\",\"DisplayName\",\"Domain\",\"New Position Tiltle\",\"Ministry\",\"User ID Description \",\"User Type\",\"AD Enabled\",\"DN\",\"ExtAttribute6\",\"MsExchExtAttribute40\",\"UserPrincipalName\",\"AzureEnabled\",\"GsuiteEmail\",\"GsuiteEnabled\",\"GsuiteAccountId\"\n");
    List records = finalDataMap.get("dataList");    
    i = 1;

    for (String rec: records) {
      dataBuilder.append(i.toString());
      dataBuilder.append(",");
      dataBuilder.append(rec);
      dataBuilder.append("\n");
      i++;      
    }
    finalRecords = dataBuilder.toString().replaceAll("null", "");   
    mailargs.put("startDate",startDateOnEmail);
    mailargs.put("endDate",endDateOnEmail);
    mailargs.put("currentDate",currentDateTime);
    mailopts = new EmailOptions(toAddress, mailargs);
    attachment = new EmailFileAttachment(fileName, EmailFileAttachment.MimeType.MIME_CSV, finalRecords.getBytes("UTF-8"));   
    mailopts.addAttachment(attachment);
    context.sendEmailNotification(template, mailopts);
    return true;
  }

  //Below code will get the list and send the report to the toAddress
  Map finalData = new HashMap();
  List toAddressList = new ArrayList();
  String stDate = null;
  String enDate = null;
  String toAddress = null;

  long startDate;
  long endDate;
  String taskName;

  String launcher = null;
  String launcherValue = null;

  Custom custom = context.getObjectByName(Custom.class,"Ascension-Custom-Rehire-Configuration");
  if(null!=custom){
    Map reportEmailToAddress = custom.get("Report Email Address");
    if(null != reportEmailToAddress){
      toAddressList = reportEmailToAddress.get("to");
    }
  }
  toAddress = String.join(",", toAddressList); 
  if (null != config && config instanceof Map && !config.isEmpty()) {
    stDate = config.get("startDate");
    enDate = config.get("endDate");
    taskName =  config.get("taskName");
  }
  if(stDate != null && enDate != null && taskName.equalsIgnoreCase("Ascension-TaskDefinition-GenerateRehireReport")){
    //if it is a adhoc run
    SimpleDateFormat sdf = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss a");
    Date date1 = sdf.parse(stDate);
    Date date2 = sdf.parse(enDate);
    startDate = date1.getTime();
    endDate = date2.getTime();

    launcherValue = taskResult.getLauncher();
    Identity identityObj = context.getObjectByName(Identity.class,launcherValue);
    launcher = identityObj.getEmail();

  } else{
    //if it is a scheduled task

    //Getting the date from TaskResult for last refresh.
    String sqlStatement = "select COMPLETED from spt_task_result where name like '"+TASKDEFINITION+" -%' and completion_status='Success' order by created desc ";

    Iterator taskResultIterator = context.search("sql: " +sqlStatement,null,null);

    if(taskResultIterator!=null && taskResultIterator.hasNext()){

      lastCompletedDate = (taskResultIterator.next()).toString();

      startDate = Long.valueOf(lastCompletedDate).longValue();

      error(logName, "taskCreatedDate:: " + startDate);

      endDate = System.currentTimeMillis();

      error(logName, "endDate:: " + endDate);

    }else{     
      startDate = System.currentTimeMillis()-1;
      endDate = System.currentTimeMillis();
    }
    launcher = toAddress;
  }

  List listOfRehireIdentities = getRehiredIdentities(startDate, endDate,launcher);

  if(null != listOfRehireIdentities && !listOfRehireIdentities.isEmpty()){
    finalData.put("dataList",listOfRehireIdentities);
    sendEmail(finalData,toAddress,startDate,endDate);
  }else{
    error(logName, " ---- No rehire event got triggered from the last run of the task -- ");
  }
